  duration: number;
  resolution: string;
  aspectRatio: "16:9" | "9:16";
  prompt: string;
  referenceList?: ReferenceList[];
  audio?: boolean;
  mode: VideoMode[];
}

interface TTSConfig {
  text: string;
  voice: string;
  speechRate: number;
  pitchRate: number;
  volume: number;
  referenceList?: Extract<ReferenceList, { type: "audio" }>[];
}

interface PollResult {
  completed: boolean;
  data?: string;
  error?: string;
}

// ============================================================
// 
// ============================================================

declare const axios: any; // HTTP
declare const logger: (msg: string) => void; // 
declare const jsonwebtoken: any; // JWT
declare const zipImage: (base64: string, size: number) => Promise<string>; // ，base64
declare const zipImageResolution: (
  base64: string,
  w: number,
  h: number,
) => Promise<string>; // ，base64
