      throw new Error(`，: ${queryResponse.status}, : ${errorText}`);
    }
    const queryData = await queryResponse.json();
    const status = queryData?.state ?? queryData?.data?.state;
    const fail_reason = queryData?.data?.err_code ?? queryData?.data;
    switch (status) {
      case "completed":
      case "SUCCESS":
      case "success":
        return { completed: true, data: queryData.creations };
      case "FAILURE":
      case "failed":
        return { completed: false, error: fail_reason || "" };
      default:
        return { completed: false };
    }
  });
  if (res.error) throw new Error(res.error);
  return res;
};

